class Solution {
public:
    vector<bool> canMakePalindromeQueries(string s, vector<vector<int>>& queries) {
        vector<bool> result;
        int n = s.length();
        for (auto& query : queries) {
            int a = query[0], b = query[1], c = query[2], d = query[3];
            string left = s.substr(a, b - a + 1);
            string right = s.substr(c, d - c + 1);
            string mid = s.substr(b + 1, c - b - 1);
            unordered_map<char, int> leftCount, rightCount, midCount;
            for (char ch : left) leftCount[ch]++;
            for (char ch : right) rightCount[ch]++;
            for (char ch : mid) midCount[ch]++;
            bool possible = true;
            for (auto& pair : midCount) {
                if (pair.second % 2 != 0) {
                    if (leftCount[pair.first] == 0 && rightCount[pair.first] == 0) {
                        possible = false;
                        break;
                    }
                }
            }
            result.push_back(possible);
        }
        return result;
    }
};

